\title{Uniformity in Mordell--Lang for curves}
%Alternative: \title{Uniform Mordell--Lang for curves and given rank}

\author{Vesselin Dimitrov, Ziyang Gao and Philipp Habegger}

\address{Department of Mathematics, University of Toronto, 40 St. George Street, Toronto, Ontario, Canada M5S 2E4}
\email{dimitrov@math.toronto.edu}
\address{CNRS, IMJ-PRG, 4 place Jussieu, 75005 Paris, France}
\email{ziyang.gao@imj-prg.fr}
